module RefModule(
output reg [3:0] n_ascci,
input clk,
input add_ascci,
input reset_ascci
 );reg [3:0] final_sig;
always @(posedge clk) begin
		if (reset_ascci == 1)	final_sig <= 4'b0000;
		else if (add_ascci == 1) final_sig <= final_sig+1;
			else final_sig<=final_sig;
		end	
always @(final_sig) begin
		n_ascci <= final_sig;
	end
endmodule
